-    if (match(I, m_Intrinsic<Intrinsic::maximum>(m_Value(), m_Value())))
-      return RecurKind::FMaximum;
-    if (match(I, m_Intrinsic<Intrinsic::minimum>(m_Value(), m_Value())))
-      return RecurKind::FMinimum;
